def findKthNumber(n, k):
    def count(p1, p2):
        steps = 0
        while p1 <= n:
            steps += min(n + 1, p2) - p1
            p1 *= 10; p2 *= 10
        return steps
    cur = 1; k -= 1
    while k > 0:
        s = count(cur, cur + 1)
        if k >= s: k -= s; cur += 1
        else: k -= 1; cur *= 10
    return cur

